% Baseline names
\newcommand{\baselineA}{\textsc{Method-A}\xspace}
\newcommand{\baselineB}{\textsc{Method-B}\xspace}
\newcommand{\baselineC}{\textsc{Baseline}\xspace}

% Table helpers
